window.KJV1769_STRONG_BOOKS["Phil"] = {"osis":"Phil","book":"빌립보서","verses":{"1:1":{"text":"Paul and Timotheus, the servants of Jesus Christ, to all the saints in Christ Jesus which are at Philippi, with the bishops and deacons:","words":[["G3972","Paul",0,4],["G2532","and",5,8],["G5095","Timotheus",9,18],["G1401","the servants",20,32],["G2424","of Jesus",33,41],["G5547","Christ",42,48],["G3956","to all",50,56],["G0040","the saints",57,67],["G1722","in",68,70],["G5547","Christ",71,77],["G2424","Jesus",78,83],["G5607","which are",84,93],["G1722","at",94,96],["G5375","Philippi",97,105],["G4862","with",107,111],["G1985","the bishops",112,123],["G2532","and",124,127],["G1249","deacons",128,135]]},"1:2":{"text":"Grace be unto you, and peace, from God our Father, and from the Lord Jesus Christ.","words":[["G5485","Grace",0,5],["G5213","be unto you",6,17],["G2532","and",19,22],["G1515","peace",23,28],["G0575","from",30,34],["G2316","God",35,38],["G2257","our",39,42],["G3962","Father",43,49],["G2532","and",51,54],["G2962","from the Lord",55,68],["G2424","Jesus",69,74],["G5547","Christ",75,81]]},"1:3":{"text":"I thank my God upon every remembrance of you,","words":[["G2168","I thank",0,7],["G3450","my",8,10],["G2316","God",11,14],["G1909","upon",15,19],["G3956","every",20,25],["G3417","remembrance",26,37],["G5216","of you",38,44]]},"1:4":{"text":"Always in every prayer of mine for you all making request with joy,","words":[["G3842","Always",0,6],["G1722","in",7,9],["G3956","every",10,15],["G1162","prayer",16,22],["G3450","of mine",23,30],["G5228","for",31,34],["G5216","you",35,38],["G3956","all",39,42],["G4160","making",43,49],["G1162","request",50,57],["G3326","with",58,62],["G5479","joy",63,66]]},"1:5":{"text":"For your fellowship in the gospel from the first day until now;","words":[["G1909","For",0,3],["G5216","your",4,8],["G2842","fellowship",9,19],["G1519","in",20,22],["G2098","the gospel",23,33],["G0575","from",34,38],["G4413","the first",39,48],["G2250","day",49,52],["G0891","until",53,58],["G3568","now",59,62]]},"1:6":{"text":"Being confident of this very thing, that he which hath begun a good work in you will perform it until the day of Jesus Christ:","words":[["G3982","Being confident",0,15],["G5124","of this",16,23],["G0846","very thing",24,34],["G3754","that",36,40],["G1728","he which hath begun",41,60],["G0018","a good",61,67],["G2041","work",68,72],["G1722","in",73,75],["G5213","you",76,79],["G2005","will perform",80,92],["G0891","it until",93,101],["G2250","the day",102,109],["G2424","of Jesus",110,118],["G5547","Christ",119,125]]},"1:7":{"text":"Even as it is meet for me to think this of you all, because I have you in my heart; inasmuch as both in my bonds, and in the defence and confirmation of the gospel, ye all are partakers of my grace.","words":[["G2531","Even as",0,7],["G2076","it is",8,13],["G1342","meet",14,18],["G1698","for me",19,25],["G5426","to think",26,34],["G5124","this",35,39],["G5228","of",40,42],["G5216","you",43,46],["G3956","all",47,50],["G1223","because",52,59],["G2192","I have",60,66],["G5209","you",67,70],["G1722","in",71,73],["G3165","my",74,76],["G2588","heart",77,82],["G5037","inasmuch as both",84,100],["G1722","in",101,103],["G3450","my",104,106],["G1199","bonds",107,112],["G2532","and",114,117],["G0627","in the defence",118,132],["G2532","and",133,136],["G0951","confirmation",137,149],["G2098","of the gospel",150,163],["G5209","ye",165,167],["G3956","all",168,171],["G5607","are",172,175],["G4791","partakers",176,185],["G3450","of my",186,191],["G5485","grace",192,197]]},"1:8":{"text":"For God is my record, how greatly I long after you all in the bowels of Jesus Christ.","words":[["G1063","For",0,3],["G2316","God",4,7],["G2076","is",8,10],["G3450","my",11,13],["G3144","record",14,20],["G5613","how",22,25],["G1971","greatly I long after",26,46],["G5209","you",47,50],["G3956","all",51,54],["G1722","in",55,57],["G4698","the bowels",58,68],["G2424","of Jesus",69,77],["G5547","Christ",78,84]]},"1:9":{"text":"And this I pray, that your love may abound yet more and more in knowledge and in all judgment;","words":[["G2532","And",0,3],["G5124","this",4,8],["G4336","I pray",9,15],["G2443","that",17,21],["G5216","your",22,26],["G0026","love",27,31],["G4052","may abound",32,42],["G2089","yet",43,46],["G3123","more",47,51],["G2532","and",52,55],["G3123","more",56,60],["G1722","in",61,63],["G1922","knowledge",64,73],["G2532","and",74,77],["G3956","in all",78,84],["G0144","judgment",85,93]]},"1:10":{"text":"That ye may approve things that are excellent; that ye may be sincere and without offence till the day of Christ;","words":[["G1519","That",0,4],["G5209","ye",5,7],["G1381","may approve",8,19],["G1308","things that are excellent",20,45],["G2443","that",47,51],["G5600","ye may be",52,61],["G1506","sincere",62,69],["G2532","and",70,73],["G0677","without offence",74,89],["G1519","till",90,94],["G2250","the day",95,102],["G5547","of Christ",103,112]]},"1:11":{"text":"Being filled with the fruits of righteousness, which are by Jesus Christ, unto the glory and praise of God.","words":[["G4137","Being filled",0,12],["G2590","with the fruits",13,28],["G1343","of righteousness",29,45],["G3588","which",47,52],["G1223","are by",53,59],["G2424","Jesus",60,65],["G5547","Christ",66,72],["G1519","unto",74,78],["G1391","the glory",79,88],["G2532","and",89,92],["G1868","praise",93,99],["G2316","of God",100,106]]},"1:12":{"text":"But I would ye should understand, brethren, that the things which happened unto me have fallen out rather unto the furtherance of the gospel;","words":[["G1161","But",0,3],["G1014","I would",4,11],["G5209","ye",12,14],["G1097","should understand",15,32],["G0080","brethren",34,42],["G3754","that",44,48],["G2596","the things which happened unto",49,79],["G1691","me",80,82],["G2064","have fallen out",83,98],["G3123","rather",99,105],["G1519","unto",106,110],["G4297","the furtherance",111,126],["G2098","of the gospel",127,140]]},"1:13":{"text":"So that my bonds in Christ are manifest in all the palace, and in all other places;","words":[["G5620","So that",0,7],["G3450","my",8,10],["G1199","bonds",11,16],["G1722","in",17,19],["G5547","Christ",20,26],["G1096","are",27,30],["G5318","manifest",31,39],["G1722","in",40,42],["G3650","all",43,46],["G4232","the palace",47,57],["G2532","and",59,62],["G3956","in all",63,69],["G3062","other",70,75]]},"1:14":{"text":"And many of the brethren in the Lord, waxing confident by my bonds, are much more bold to speak the word without fear.","words":[["G2532","And",0,3],["G4119","many",4,8],["G0080","of the brethren",9,24],["G1722","in",25,27],["G2962","the Lord",28,36],["G3982","waxing confident",38,54],["G3450","by my",55,60],["G1199","bonds",61,66],["G4056","are much more",68,81],["G5111","bold",82,86],["G2980","to speak",87,95],["G3056","the word",96,104],["G0870","without fear",105,117]]},"1:15":{"text":"Some indeed preach Christ even of envy and strife; and some also of good will:","words":[["G5100","Some",0,4],["G3303","indeed",5,11],["G2784","preach",12,18],["G5547","Christ",19,25],["G2532","even",26,30],["G1223","of",31,33],["G5355","envy",34,38],["G2532","and",39,42],["G2054","strife",43,49],["G1161","and",51,54],["G5100","some",55,59],["G2532","also",60,64],["G1223","of",65,67],["G2107","good will",68,77]]},"1:16":{"text":"The one preach Christ of contention, not sincerely, supposing to add affliction to my bonds:","words":[["G3303","The one",0,7],["G2605","preach",8,14],["G5547","Christ",15,21],["G1537","of",22,24],["G2052","contention",25,35],["G3756","not",37,40],["G0055","sincerely",41,50],["G3633","supposing",52,61],["G2018","to add",62,68],["G2347","affliction",69,79],["G3450","to my",80,85],["G1199","bonds",86,91]]},"1:17":{"text":"But the other of love, knowing that I am set for the defence of the gospel.","words":[["G1161","But",0,3],["G1537","the other of",4,16],["G0026","love",17,21],["G1492","knowing",23,30],["G3754","that",31,35],["G2749","I am set",36,44],["G1519","for",45,48],["G0627","the defence",49,60],["G2098","of the gospel",61,74]]},"1:18":{"text":"What then? notwithstanding, every way, whether in pretence, or in truth, Christ is preached; and I therein do rejoice, yea, and will rejoice.","words":[["G5101","What",0,4],["G1063","then",5,9],["G4133","notwithstanding",11,26],["G3956","every",28,33],["G5158","way",34,37],["G1535","whether",39,46],["G4392","in pretence",47,58],["G1535","or",60,62],["G0225","in truth",63,71],["G5547","Christ",73,79],["G2605","is preached",80,91],["G2532","and",93,96],["G5463","I",97,98],["G1722","therein",99,106],["G5129","therein",99,106],["G5463","do rejoice",107,117],["G0235","yea",119,122],["G2532","and",124,127],["G5463","will rejoice",128,140]]},"1:19":{"text":"For I know that this shall turn to my salvation through your prayer, and the supply of the Spirit of Jesus Christ,","words":[["G1063","For",0,3],["G1492","I know",4,10],["G3754","that",11,15],["G5124","this",16,20],["G0576","shall turn",21,31],["G1519","to",32,34],["G3427","my",35,37],["G4991","salvation",38,47],["G1223","through",48,55],["G5216","your",56,60],["G1162","prayer",61,67],["G2532","and",69,72],["G2024","the supply",73,83],["G4151","of the Spirit",84,97],["G2424","of Jesus",98,106],["G5547","Christ",107,113]]},"1:20":{"text":"According to my earnest expectation and my hope, that in nothing I shall be ashamed, but that with all boldness, as always, so now also Christ shall be magnified in my body, whether it be by life, or by death.","words":[["G2596","According",0,9],["G3450","to my",10,15],["G0603","earnest expectation",16,35],["G2532","and",36,39],["G1680","my hope",40,47],["G3754","that",49,53],["G1722","in",54,56],["G3762","nothing",57,64],["G0153","I shall be ashamed",65,83],["G0235","but",85,88],["G1722","that with",89,98],["G3956","all",99,102],["G3954","boldness",103,111],["G5613","as",113,115],["G3842","always",116,122],["G3568","so now",124,130],["G2532","also",131,135],["G5547","Christ",136,142],["G3170","shall be magnified",143,161],["G1722","in",162,164],["G3450","my",165,167],["G4983","body",168,172],["G1535","whether",174,181],["G1223","it be by",182,190],["G2222","life",191,195],["G1535","or",197,199],["G1223","by",200,202],["G2288","death",203,208]]},"1:21":{"text":"For to me to live is Christ, and to die is gain.","words":[["G1063","For",0,3],["G1698","to me",4,9],["G2198","to live",10,17],["G5547","is Christ",18,27],["G2532","and",29,32],["G0599","to die",33,39],["G2771","is gain",40,47]]},"1:22":{"text":"But if I live in the flesh, this is the fruit of my labour: yet what I shall choose I wot not.","words":[["G1161","But",0,3],["G1487","if",4,6],["G2198","I live",7,13],["G1722","in",14,16],["G4561","the flesh",17,26],["G5124","this",28,32],["G2590","is the fruit",33,45],["G2041","of my labour",46,58],["G3427","of my labour",46,58],["G2532","yet",60,63],["G5101","what",64,68],["G0138","I shall choose",69,83],["G1107","I wot",84,89],["G3756","not",90,93]]},"1:23":{"text":"For I am in a strait betwixt two, having a desire to depart, and to be with Christ; which is far better:","words":[["G1063","For",0,3],["G4912","I am in a strait",4,20],["G1537","betwixt",21,28],["G1417","two",29,32],["G2192","having",34,40],["G1939","a desire",41,49],["G1519","to",50,52],["G0360","depart",53,59],["G2532","and",61,64],["G1511","to be",65,70],["G4862","with",71,75],["G5547","Christ",76,82],["G4183","which is far",84,96],["G3123","which is far",84,96],["G2908","better",97,103]]},"1:24":{"text":"Nevertheless to abide in the flesh is more needful for you.","words":[["G1161","Nevertheless",0,12],["G1961","to abide",13,21],["G1722","in",22,24],["G4561","the flesh",25,34],["G0316","is more needful",35,50],["G1223","for",51,54],["G5209","you",55,58]]},"1:25":{"text":"And having this confidence, I know that I shall abide and continue with you all for your furtherance and joy of faith;","words":[["G2532","And",0,3],["G5124","having this",4,15],["G3982","confidence",16,26],["G1492","I know",28,34],["G3754","that",35,39],["G3306","I shall abide",40,53],["G2532","and",54,57],["G4839","continue",58,66],["G5213","with you",67,75],["G3956","all",76,79],["G1519","for",80,83],["G5216","your",84,88],["G4297","furtherance",89,100],["G2532","and",101,104],["G5479","joy",105,108],["G4102","of faith",109,117]]},"1:26":{"text":"That your rejoicing may be more abundant in Jesus Christ for me by my coming to you again.","words":[["G2443","That",0,4],["G5216","your",5,9],["G2745","rejoicing",10,19],["G4052","may be more abundant",20,40],["G1722","in",41,43],["G2424","Jesus",44,49],["G5547","Christ",50,56],["G1722","for",57,60],["G1698","me",61,63],["G1223","by",64,66],["G1699","my",67,69],["G3952","coming",70,76],["G4314","to",77,79],["G5209","you",80,83],["G3825","again",84,89]]},"1:27":{"text":"Only let your conversation be as it becometh the gospel of Christ: that whether I come and see you, or else be absent, I may hear of your affairs, that ye stand fast in one spirit, with one mind striving together for the faith of the gospel;","words":[["G3440","Only",0,4],["G4176","let your conversation be",5,29],["G0516","as it becometh",30,44],["G2098","the gospel",45,55],["G5547","of Christ",56,65],["G2443","that",67,71],["G1535","whether",72,79],["G2064","I come",80,86],["G2532","and",87,90],["G1492","see",91,94],["G5209","you",95,98],["G1535","or",100,102],["G0548","else be absent",103,117],["G0191","I may hear",119,129],["G5216","of your",130,137],["G4012","affairs",138,145],["G3754","that",147,151],["G4739","ye stand fast",152,165],["G1722","in",166,168],["G1520","one",169,172],["G4151","spirit",173,179],["G3391","with one",181,189],["G5590","mind",190,194],["G4866","striving together",195,212],["G4102","for the faith",213,226],["G2098","of the gospel",227,240]]},"1:28":{"text":"And in nothing terrified by your adversaries: which is to them an evident token of perdition, but to you of salvation, and that of God.","words":[["G2532","And",0,3],["G1722","in",4,6],["G3367","nothing",7,14],["G3361","nothing",7,14],["G4426","terrified",15,24],["G5259","by",25,27],["G0480","your adversaries",28,44],["G3748","which",46,51],["G2076","is",52,54],["G0846","to them",55,62],["G3303","to them",55,62],["G1732","an evident token",63,79],["G0684","of perdition",80,92],["G1161","but",94,97],["G5213","to you",98,104],["G4991","of salvation",105,117],["G2532","and",119,122],["G5124","that",123,127],["G0575","of",128,130],["G2316","God",131,134]]},"1:29":{"text":"For unto you it is given in the behalf of Christ, not only to believe on him, but also to suffer for his sake;","words":[["G3754","For",0,3],["G5213","unto you",4,12],["G5483","it is given",13,24],["G5228","in the behalf",25,38],["G5547","of Christ",39,48],["G3756","not",50,53],["G3440","only",54,58],["G4100","to believe",59,69],["G1519","on",70,72],["G0846","him",73,76],["G0235","but",78,81],["G2532","also",82,86],["G3958","to suffer",87,96],["G5228","for",97,100],["G0846","his sake",101,109],["G5228","his sake",101,109]]},"1:30":{"text":"Having the same conflict which ye saw in me, and now hear to be in me.","words":[["G2192","Having",0,6],["G0846","the same",7,15],["G0073","conflict",16,24],["G3634","which",25,30],["G1492","ye saw",31,37],["G1492","ye saw",31,37],["G1722","in",38,40],["G1698","me",41,43],["G2532","and",45,48],["G3568","now",49,52],["G0191","hear",53,57],["G1722","to be in",58,66],["G1698","me",67,69]]},"2:1":{"text":"If there be therefore any consolation in Christ, if any comfort of love, if any fellowship of the Spirit, if any bowels and mercies,","words":[["G3767","If there be therefore",0,21],["G1536","any",22,25],["G3874","consolation",26,37],["G1722","in",38,40],["G5547","Christ",41,47],["G1536","if any",49,55],["G3890","comfort",56,63],["G0026","of love",64,71],["G1536","if any",73,79],["G2842","fellowship",80,90],["G4151","of the Spirit",91,104],["G1536","if any",106,112],["G4698","bowels",113,119],["G2532","and",120,123],["G3628","mercies",124,131]]},"2:2":{"text":"Fulfil ye my joy, that ye be likeminded, having the same love, being of one accord, of one mind.","words":[["G4137","Fulfil ye",0,9],["G3450","my",10,12],["G5479","joy",13,16],["G2443","that",18,22],["G0846","ye be likeminded",23,39],["G5426","ye be likeminded",23,39],["G2192","having",41,47],["G0846","the same",48,56],["G0026","love",57,61],["G4861","being of one accord",63,82],["G1520","of one",84,90],["G5426","mind",91,95]]},"2:3":{"text":"Let nothing be done through strife or vainglory; but in lowliness of mind let each esteem other better than themselves.","words":[["G3367","Let nothing",0,11],["G2596","be done through",12,27],["G2052","strife",28,34],["G2228","or",35,37],["G2754","vainglory",38,47],["G0235","but",49,52],["G5012","in lowliness of mind",53,73],["G2233","let",74,77],["G0240","each",78,82],["G2233","esteem",83,89],["G0240","other",90,95],["G5242","better than",96,107],["G1438","themselves",108,118]]},"2:4":{"text":"Look not every man on his own things, but every man also on the things of others.","words":[["G4648","Look",0,4],["G3361","not",5,8],["G1538","every man",9,18],["G1438","on his own things",19,36],["G0235","but",38,41],["G1538","every man",42,51],["G2532","also",52,56],["G3588","on the things",57,70],["G2087","of others",71,80]]},"2:5":{"text":"Let this mind be in you, which was also in Christ Jesus:","words":[["G1063","",-1,-1],["G5426","Let",0,3],["G5124","this",4,8],["G5426","mind be",9,16],["G1722","in",17,19],["G5213","you",20,23],["G3739","which",25,30],["G2532","was also",31,39],["G1722","in",40,42],["G5547","Christ",43,49],["G2424","Jesus",50,55]]},"2:6":{"text":"Who, being in the form of God, thought it not robbery to be equal with God:","words":[["G3739","Who",0,3],["G5225","being",5,10],["G1722","in",11,13],["G3444","the form",14,22],["G2316","of God",23,29],["G2233","thought it",31,41],["G3756","not",42,45],["G0725","robbery",46,53],["G1511","to be",54,59],["G2470","equal",60,65],["G2316","with God",66,74]]},"2:7":{"text":"But made himself of no reputation, and took upon him the form of a servant, and was made in the likeness of men:","words":[["G0235","But",0,3],["G2758","made",4,8],["G1438","himself",9,16],["G2758","of no reputation",17,33],["G2983","and took upon him",35,52],["G3444","the form",53,61],["G1401","of a servant",62,74],["G1096","and was made",76,88],["G1722","in",89,91],["G3667","the likeness",92,104],["G0444","of men",105,111]]},"2:8":{"text":"And being found in fashion as a man, he humbled himself, and became obedient unto death, even the death of the cross.","words":[["G2532","And",0,3],["G2147","being found",4,15],["G4976","in fashion",16,26],["G5613","as",27,29],["G0444","a man",30,35],["G5013","he humbled",37,47],["G1438","himself",48,55],["G1096","and became",57,67],["G5255","obedient",68,76],["G3360","unto",77,81],["G2288","death",82,87],["G1161","even",89,93],["G2288","the death",94,103],["G4716","of the cross",104,116]]},"2:9":{"text":"Wherefore God also hath highly exalted him, and given him a name which is above every name:","words":[["G1352","Wherefore",0,9],["G2316","God",10,13],["G2532","also",14,18],["G5251","hath highly exalted",19,38],["G0846","him",39,42],["G2532","and",44,47],["G5483","given",48,53],["G0846","him",54,57],["G3686","a name",58,64],["G3588","which",65,70],["G5228","is above",71,79],["G3956","every",80,85],["G3686","name",86,90]]},"2:10":{"text":"That at the name of Jesus every knee should bow, of things in heaven, and things in earth, and things under the earth;","words":[["G2443","That",0,4],["G1722","at",5,7],["G3686","the name",8,16],["G2424","of Jesus",17,25],["G3956","every",26,31],["G1119","knee",32,36],["G2578","should bow",37,47],["G2032","of things in heaven",49,68],["G2532","and",70,73],["G1919","things in earth",74,89],["G2532","and",91,94],["G2709","things under the earth",95,117]]},"2:11":{"text":"And that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father.","words":[["G2532","And",0,3],["G3956","that every",4,14],["G1100","tongue",15,21],["G1843","should confess",22,36],["G3754","that",37,41],["G2424","Jesus",42,47],["G5547","Christ",48,54],["G2962","is Lord",55,62],["G1519","to",64,66],["G1391","the glory",67,76],["G2316","of God",77,83],["G3962","the Father",84,94]]},"2:12":{"text":"Wherefore, my beloved, as ye have always obeyed, not as in my presence only, but now much more in my absence, work out your own salvation with fear and trembling.","words":[["G5620","Wherefore",0,9],["G3450","my",11,13],["G0027","beloved",14,21],["G2531","as",23,25],["G5219","ye have",26,33],["G3842","always",34,40],["G5219","obeyed",41,47],["G3361","not",49,52],["G5613","as",53,55],["G1722","in",56,58],["G3450","my",59,61],["G3952","presence",62,70],["G3440","only",71,75],["G0235","but",77,80],["G3568","now",81,84],["G4183","much",85,89],["G3123","more",90,94],["G1722","in",95,97],["G3450","my",98,100],["G0666","absence",101,108],["G2716","work out",110,118],["G1438","your own",119,127],["G4991","salvation",128,137],["G3326","with",138,142],["G5401","fear",143,147],["G2532","and",148,151],["G5156","trembling",152,161]]},"2:13":{"text":"For it is God which worketh in you both to will and to do of his good pleasure.","words":[["G1063","For",0,3],["G2076","it is",4,9],["G2316","God",10,13],["G3588","which",14,19],["G1754","worketh",20,27],["G1722","in",28,30],["G5213","you",31,34],["G2532","both",35,39],["G2309","to will",40,47],["G2532","and",48,51],["G1754","to do",52,57],["G5228","of",58,60],["G2107","his good pleasure",61,78]]},"2:14":{"text":"Do all things without murmurings and disputings:","words":[["G4160","Do",0,2],["G3956","all things",3,13],["G5565","without",14,21],["G1112","murmurings",22,32],["G2532","and",33,36],["G1261","disputings",37,47]]},"2:15":{"text":"That ye may be blameless and harmless, the sons of God, without rebuke, in the midst of a crooked and perverse nation, among whom ye shine as lights in the world;","words":[["G2443","That",0,4],["G1096","ye may be",5,14],["G0273","blameless",15,24],["G2532","and",25,28],["G0185","harmless",29,37],["G5043","the sons",39,47],["G2316","of God",48,54],["G0298","without rebuke",56,70],["G1722","in",72,74],["G3319","the midst",75,84],["G4646","of a crooked",85,97],["G2532","and",98,101],["G1294","perverse",102,110],["G1074","nation",111,117],["G1722","among",119,124],["G3739","whom",125,129],["G5316","ye shine",130,138],["G5613","as",139,141],["G5458","lights",142,148],["G1722","in",149,151],["G2889","the world",152,161]]},"2:16":{"text":"Holding forth the word of life; that I may rejoice in the day of Christ, that I have not run in vain, neither laboured in vain.","words":[["G1907","Holding forth",0,13],["G3056","the word",14,22],["G2222","of life",23,30],["G1519","that",32,36],["G1698","I",37,38],["G2745","may rejoice",39,50],["G1519","in",51,53],["G2250","the day",54,61],["G5547","of Christ",62,71],["G3754","that",73,77],["G5143","I have",78,84],["G3756","not",85,88],["G5143","run",89,92],["G1519","in",93,95],["G2756","vain",96,100],["G3761","neither",102,109],["G2872","laboured",110,118],["G1519","in",119,121],["G2756","vain",122,126]]},"2:17":{"text":"Yea, and if I be offered upon the sacrifice and service of your faith, I joy, and rejoice with you all.","words":[["G0235","Yea",0,3],["G1499","and if",5,11],["G4689","I be offered",12,24],["G1909","upon",25,29],["G2378","the sacrifice",30,43],["G2532","and",44,47],["G3009","service",48,55],["G5216","of your",56,63],["G4102","faith",64,69],["G5463","I joy",71,76],["G2532","and",78,81],["G4796","rejoice with",82,94],["G5213","you",95,98],["G3956","all",99,102]]},"2:18":{"text":"For the same cause also do ye joy, and rejoice with me.","words":[["G1161","For",0,3],["G0846","the same cause",4,18],["G2532","also",19,23],["G5463","do",24,26],["G5210","ye",27,29],["G5463","joy",30,33],["G2532","and",35,38],["G4796","rejoice with",39,51],["G3427","me",52,54]]},"2:19":{"text":"But I trust in the Lord Jesus to send Timotheus shortly unto you, that I also may be of good comfort, when I know your state.","words":[["G1161","But",0,3],["G1679","I trust",4,11],["G1722","in",12,14],["G2962","the Lord",15,23],["G2424","Jesus",24,29],["G3992","to send",30,37],["G5095","Timotheus",38,47],["G5030","shortly",48,55],["G5213","unto you",56,64],["G2443","that",66,70],["G2504","I also",71,77],["G2174","may be of good comfort",78,100],["G1097","when I know",102,113],["G5216","your",114,118],["G4012","state",119,124]]},"2:20":{"text":"For I have no man likeminded, who will naturally care for your state.","words":[["G1063","For",0,3],["G2192","I have",4,10],["G3762","no man",11,17],["G2473","likeminded",18,28],["G3748","who",30,33],["G1104","will naturally",34,48],["G3309","care",49,53],["G5216","for your",54,62],["G4012","state",63,68]]},"2:21":{"text":"For all seek their own, not the things which are Jesus Christ's.","words":[["G1063","For",0,3],["G3956","all",4,7],["G2212","seek",8,12],["G1438","their own",13,22],["G3756","not",24,27],["G3588","the things which are",28,48],["G2424","Jesus",49,54],["G5547","Christ's",55,63]]},"2:22":{"text":"But ye know the proof of him, that, as a son with the father, he hath served with me in the gospel.","words":[["G1161","But",0,3],["G1097","ye know",4,11],["G1382","the proof",12,21],["G0846","of him",22,28],["G3754","that",30,34],["G5613","as",36,38],["G5043","a son",39,44],["G3962","with the father",45,60],["G1398","he hath served",62,76],["G4862","with",77,81],["G1698","me",82,84],["G1519","in",85,87],["G2098","the gospel",88,98]]},"2:23":{"text":"Him therefore I hope to send presently, so soon as I shall see how it will go with me.","words":[["G3303","Him",0,3],["G5126","Him",0,3],["G3767","therefore",4,13],["G1679","I hope",14,20],["G3992","to send",21,28],["G1824","presently",29,38],["G5613","so soon as",40,50],["G0302","I",51,52],["G0542","shall see",53,62],["G4012","how",63,66],["G1691","it will go with me",67,85]]},"2:24":{"text":"But I trust in the Lord that I also myself shall come shortly.","words":[["G1161","But",0,3],["G3982","I trust",4,11],["G1722","in",12,14],["G2962","the Lord",15,23],["G3754","that",24,28],["G2064","I",29,30],["G2532","also",31,35],["G0846","myself",36,42],["G2064","shall come",43,53],["G5030","shortly",54,61]]},"2:25":{"text":"Yet I supposed it necessary to send to you Epaphroditus, my brother, and companion in labour, and fellowsoldier, but your messenger, and he that ministered to my wants.","words":[["G1161","Yet",0,3],["G2233","I supposed",4,14],["G0316","it necessary",15,27],["G3992","to send",28,35],["G4314","to",36,38],["G5209","you",39,42],["G1891","Epaphroditus",43,55],["G3450","my",57,59],["G0080","brother",60,67],["G2532","and",69,72],["G4904","companion in labour",73,92],["G2532","and",94,97],["G4961","fellowsoldier",98,111],["G1161","but",113,116],["G5216","your",117,121],["G0652","messenger",122,131],["G2532","and",133,136],["G3011","he that ministered",137,155],["G3450","to my",156,161],["G5532","wants",162,167]]},"2:26":{"text":"For he longed after you all, and was full of heaviness, because that ye had heard that he had been sick.","words":[["G1894","For",0,3],["G2258","he",4,6],["G1971","longed after",7,19],["G5209","you",20,23],["G3956","all",24,27],["G2532","and",29,32],["G0085","was full of heaviness",33,54],["G1360","because",56,63],["G0191","that ye had heard",64,81],["G3754","that",82,86],["G0770","he had been sick",87,103]]},"2:27":{"text":"For indeed he was sick nigh unto death: but God had mercy on him; and not on him only, but on me also, lest I should have sorrow upon sorrow.","words":[["G1063","For",0,3],["G2532","indeed",4,10],["G0770","he was sick",11,22],["G3897","nigh",23,27],["G2288","unto death",28,38],["G0235","but",40,43],["G2316","God",44,47],["G1653","had mercy",48,57],["G0846","on him",58,64],["G1161","and",66,69],["G3756","not",70,73],["G0846","on him",74,80],["G3440","only",81,85],["G0235","but",87,90],["G1691","on me",91,96],["G2532","also",97,101],["G3363","lest",103,107],["G2192","I should have",108,121],["G3077","sorrow",122,128],["G1909","upon",129,133],["G3077","sorrow",134,140]]},"2:28":{"text":"I sent him therefore the more carefully, that, when ye see him again, ye may rejoice, and that I may be the less sorrowful.","words":[["G3992","I sent",0,6],["G0846","him",7,10],["G3767","therefore",11,20],["G4708","the more carefully",21,39],["G2443","that",41,45],["G1492","when ye see",47,58],["G0846","him",59,62],["G3825","again",63,68],["G5463","ye may rejoice",70,84],["G2504","and that I",86,96],["G5600","may be",97,103],["G0253","the less sorrowful",104,122]]},"2:29":{"text":"Receive him therefore in the Lord with all gladness; and hold such in reputation:","words":[["G4327","Receive",0,7],["G0846","him",8,11],["G3767","therefore",12,21],["G1722","in",22,24],["G2962","the Lord",25,33],["G3326","with",34,38],["G3956","all",39,42],["G5479","gladness",43,51],["G2532","and",53,56],["G2192","hold",57,61],["G5108","such",62,66],["G1784","in reputation",67,80]]},"2:30":{"text":"Because for the work of Christ he was nigh unto death, not regarding his life, to supply your lack of service toward me.","words":[["G3754","Because",0,7],["G1223","for",8,11],["G2041","the work",12,20],["G5547","of Christ",21,30],["G1448","he was nigh",31,42],["G3360","unto",43,47],["G2288","death",48,53],["G3851","not regarding",55,68],["G5590","his life",69,77],["G2443","to",79,81],["G0378","supply",82,88],["G5216","your",89,93],["G5303","lack",94,98],["G3009","of service",99,109],["G4314","toward",110,116],["G3165","me",117,119]]},"3:1":{"text":"Finally, my brethren, rejoice in the Lord. To write the same things to you, to me indeed is not grievous, but for you it is safe.","words":[["G3063","Finally",0,7],["G3450","my",9,11],["G0080","brethren",12,20],["G5463","rejoice",22,29],["G1722","in",30,32],["G2962","the Lord",33,41],["G1125","To write",43,51],["G0846","the same things",52,67],["G5213","to you",68,74],["G1698","to me",76,81],["G3303","indeed",82,88],["G3756","is not",89,95],["G3636","grievous",96,104],["G1161","but",106,109],["G5213","for you",110,117],["G0804","it is safe",118,128]]},"3:2":{"text":"Beware of dogs, beware of evil workers, beware of the concision.","words":[["G0991","Beware",0,6],["G2965","of dogs",7,14],["G0991","beware",16,22],["G2556","of evil",23,30],["G2040","workers",31,38],["G0991","beware",40,46],["G2699","of the concision",47,63]]},"3:3":{"text":"For we are the circumcision, which worship God in the spirit, and rejoice in Christ Jesus, and have no confidence in the flesh.","words":[["G1063","For",0,3],["G2249","we",4,6],["G2070","are",7,10],["G4061","the circumcision",11,27],["G3588","which",29,34],["G3000","worship",35,42],["G2316","God",43,46],["G4151","in the spirit",47,60],["G2532","and",62,65],["G2744","rejoice",66,73],["G1722","in",74,76],["G5547","Christ",77,83],["G2424","Jesus",84,89],["G2532","and",91,94],["G3982","have",95,99],["G3756","no",100,102],["G3982","confidence",103,113],["G1722","in",114,116],["G4561","the flesh",117,126]]},"3:4":{"text":"Though I might also have confidence in the flesh. If any other man thinketh that he hath whereof he might trust in the flesh, I more:","words":[["G2539","Though",0,6],["G1473","I",7,8],["G2192","might",9,14],["G2532","also",15,19],["G2192","have",20,24],["G4006","confidence",25,35],["G1722","in",36,38],["G4561","the flesh",39,48],["G1536","If any",50,56],["G0243","other man",57,66],["G1380","thinketh",67,75],["G3982","that he hath whereof he might trust",76,111],["G1722","in",112,114],["G4561","the flesh",115,124],["G1473","I",126,127],["G3123","more",128,132]]},"3:5":{"text":"Circumcised the eighth day, of the stock of Israel, of the tribe of Benjamin, an Hebrew of the Hebrews; as touching the law, a Pharisee;","words":[["G4061","Circumcised",0,11],["G3637","the eighth",12,22],["G1537","day, of",23,30],["G1085","the stock",31,40],["G2474","of Israel",41,50],["G5443","of the tribe",52,64],["G0958","of Benjamin",65,76],["G1445","an Hebrew",78,87],["G1537","of",88,90],["G1445","the Hebrews",91,102],["G2596","as touching",104,115],["G3551","the law",116,123],["G5330","a Pharisee",125,135]]},"3:6":{"text":"Concerning zeal, persecuting the church; touching the righteousness which is in the law, blameless.","words":[["G2596","Concerning",0,10],["G2205","zeal",11,15],["G1377","persecuting",17,28],["G1577","the church",29,39],["G2596","touching",41,49],["G1343","the righteousness",50,67],["G3588","which",68,73],["G1722","is in",74,79],["G3551","the law",80,87],["G1096","",-1,-1],["G0273","blameless",89,98]]},"3:7":{"text":"But what things were gain to me, those I counted loss for Christ.","words":[["G0235","But",0,3],["G3748","what things",4,15],["G2258","were",16,20],["G2771","gain",21,25],["G3427","to me",26,31],["G5023","those",33,38],["G2233","I counted",39,48],["G2209","loss",49,53],["G1223","for",54,57],["G5547","Christ",58,64]]},"3:8":{"text":"Yea doubtless, and I count all things but loss for the excellency of the knowledge of Christ Jesus my Lord: for whom I have suffered the loss of all things, and do count them but dung, that I may win Christ,","words":[["G0235","Yea",0,3],["G3304","doubtless",4,13],["G2532","and",15,18],["G2233","I count",19,26],["G3956","all things",27,37],["G2209","but loss",38,46],["G1511","for",47,50],["G1223","for",47,50],["G5242","the excellency",51,65],["G1108","of the knowledge",66,82],["G5547","of Christ",83,92],["G2424","Jesus",93,98],["G3450","my",99,101],["G2962","Lord",102,106],["G1223","for",108,111],["G3739","whom",112,116],["G2210","I have suffered the loss",117,141],["G3956","of all things",142,155],["G2532","and",157,160],["G2233","do count",161,169],["G1511","them",170,174],["G4657","but dung",175,183],["G2443","that",185,189],["G2770","I may win",190,199],["G5547","Christ",200,206]]},"3:9":{"text":"And be found in him, not having mine own righteousness, which is of the law, but that which is through the faith of Christ, the righteousness which is of God by faith:","words":[["G2532","And",0,3],["G2147","be found",4,12],["G1722","in",13,15],["G0846","him",16,19],["G3361","not",21,24],["G2192","having",25,31],["G1699","mine own",32,40],["G1343","righteousness",41,54],["G3588","which",56,61],["G1537","is of",62,67],["G3551","the law",68,75],["G0235","but",77,80],["G3588","that which",81,91],["G1223","is through",92,102],["G4102","the faith",103,112],["G5547","of Christ",113,122],["G1343","the righteousness",124,141],["G3588","which",142,147],["G1537","is of",148,153],["G2316","God",154,157],["G1909","by",158,160],["G4102","faith",161,166]]},"3:10":{"text":"That I may know him, and the power of his resurrection, and the fellowship of his sufferings, being made conformable unto his death;","words":[["G1097","That I may know",0,15],["G0846","him",16,19],["G2532","and",21,24],["G1411","the power",25,34],["G0846","of his",35,41],["G0386","resurrection",42,54],["G2532","and",56,59],["G2842","the fellowship",60,74],["G0846","of his",75,81],["G3804","sufferings",82,92],["G4833","being made conformable",94,116],["G0846","unto his",117,125],["G2288","death",126,131]]},"3:11":{"text":"If by any means I might attain unto the resurrection of the dead.","words":[["G1513","If by any means",0,15],["G2658","I might attain",16,30],["G1519","unto",31,35],["G1815","the resurrection",36,52],["G3498","of the dead",53,64]]},"3:12":{"text":"Not as though I had already attained, either were already perfect: but I follow after, if that I may apprehend that for which also I am apprehended of Christ Jesus.","words":[["G3756","Not",0,3],["G3754","as though",4,13],["G2235","I had already",14,27],["G2983","attained",28,36],["G2228","either",38,44],["G2235","were already",45,57],["G5048","perfect",58,65],["G1161","but",67,70],["G1377","I follow after",71,85],["G1499","if",87,89],["G2638","that I may apprehend",90,110],["G1909","that for",111,119],["G3739","which",120,125],["G2532","also",126,130],["G2638","I am apprehended",131,147],["G5259","of",148,150],["G5547","Christ",151,157],["G2424","Jesus",158,163]]},"3:13":{"text":"Brethren, I count not myself to have apprehended: but this one thing I do, forgetting those things which are behind, and reaching forth unto those things which are before,","words":[["G0080","Brethren",0,8],["G1473","I",10,11],["G3049","count",12,17],["G3756","not",18,21],["G1683","myself",22,28],["G2638","to have apprehended",29,48],["G1161","but",50,53],["G1520","this one thing",54,68],["G1950","I do, forgetting",69,85],["G3303","those things",86,98],["G3694","which are behind",99,115],["G1161","and",117,120],["G1901","reaching forth unto",121,140],["G1715","those things which are before",141,170]]},"3:14":{"text":"I press toward the mark for the prize of the high calling of God in Christ Jesus.","words":[["G1377","I press",0,7],["G2596","toward",8,14],["G4649","the mark",15,23],["G1909","for",24,27],["G1017","the prize",28,37],["G0507","of the high",38,49],["G2821","calling",50,57],["G2316","of God",58,64],["G1722","in",65,67],["G5547","Christ",68,74],["G2424","Jesus",75,80]]},"3:15":{"text":"Let us therefore, as many as be perfect, be thus minded: and if in any thing ye be otherwise minded, God shall reveal even this unto you.","words":[["G5426","Let",0,3],["G3767","us therefore",4,16],["G3745","as many as",18,28],["G5046","be perfect",29,39],["G5426","be",41,43],["G5124","thus",44,48],["G5426","minded",49,55],["G2532","and",57,60],["G1536","if in any thing",61,76],["G5426","ye be",77,82],["G2088","otherwise",83,92],["G5426","minded",93,99],["G2316","God",101,104],["G0601","shall reveal",105,117],["G2532","even",118,122],["G5124","this",123,127],["G5213","unto you",128,136]]},"3:16":{"text":"Nevertheless, whereto we have already attained, let us walk by the same rule, let us mind the same thing.","words":[["G4133","Nevertheless",0,12],["G1519","whereto",14,21],["G3739","whereto",14,21],["G5348","we have already attained",22,46],["G4748","let us walk",48,59],["G0846","by the same",60,71],["G2583","rule",72,76],["G5426","let us mind",78,89],["G0846","the same thing",90,104]]},"3:17":{"text":"Brethren, be followers together of me, and mark them which walk so as ye have us for an ensample.","words":[["G0080","Brethren",0,8],["G1096","be",10,12],["G4831","followers together",13,31],["G3450","of me",32,37],["G2532","and",39,42],["G4648","mark",43,47],["G4043","them which walk",48,63],["G3779","so",64,66],["G2531","as",67,69],["G2192","ye have",70,77],["G2248","us",78,80],["G5179","for an ensample",81,96]]},"3:18":{"text":"(For many walk, of whom I have told you often, and now tell you even weeping, that they are the enemies of the cross of Christ:","words":[["G1063","(For",0,4],["G4183","many",5,9],["G4043","walk",10,14],["G3739","of whom",16,23],["G3004","I have told",24,35],["G5213","you",36,39],["G4178","often",40,45],["G1161","and",47,50],["G3568","now",51,54],["G3004","tell",55,59],["G2532","you even",60,68],["G2799","weeping",69,76],["G2190","that they are the enemies",78,103],["G4716","of the cross",104,116],["G5547","of Christ",117,126]]},"3:19":{"text":"Whose end is destruction, whose God is their belly, and whose glory is in their shame, who mind earthly things.)","words":[["G3739","Whose",0,5],["G5056","end",6,9],["G0684","is destruction",10,24],["G3739","whose",26,31],["G2316","God",32,35],["G2836","is their belly",36,50],["G2532","and",52,55],["G1391","whose glory",56,67],["G1722","is in",68,73],["G0846","their",74,79],["G0152","shame",80,85],["G3588","who",87,90],["G5426","mind",91,95],["G1919","earthly things",96,110]]},"3:20":{"text":"For our conversation is in heaven; from whence also we look for the Saviour, the Lord Jesus Christ:","words":[["G1063","For",0,3],["G2257","our",4,7],["G4175","conversation",8,20],["G5225","is",21,23],["G1722","in",24,26],["G3772","heaven",27,33],["G1537","from",35,39],["G3739","whence",40,46],["G2532","also",47,51],["G0553","we look for",52,63],["G4990","the Saviour",64,75],["G2962","the Lord",77,85],["G2424","Jesus",86,91],["G5547","Christ",92,98]]},"3:21":{"text":"Who shall change our vile body, that it may be fashioned like unto his glorious body, according to the working whereby he is able even to subdue all things unto himself.","words":[["G3739","Who",0,3],["G3345","shall change",4,16],["G2257","our",17,20],["G5014","vile",21,25],["G4983","body",26,30],["G1519","that",32,36],["G0846","it",37,39],["G1096","may be",40,46],["G4832","fashioned like unto",47,66],["G0846","his",67,70],["G1391","glorious",71,79],["G4983","body",80,84],["G2596","according to",86,98],["G1753","the working",99,110],["G0846","whereby he",111,121],["G1410","is able",122,129],["G2532","even",130,134],["G5293","to subdue",135,144],["G3956","all things",145,155],["G1438","unto himself",156,168]]},"4:1":{"text":"Therefore, my brethren dearly beloved and longed for, my joy and crown, so stand fast in the Lord, my dearly beloved.","words":[["G5620","Therefore",0,9],["G3450","my",11,13],["G0080","brethren",14,22],["G0027","dearly beloved",23,37],["G2532","and",38,41],["G1973","longed for",42,52],["G3450","my",54,56],["G5479","joy",57,60],["G2532","and",61,64],["G4735","crown",65,70],["G3779","so",72,74],["G4739","stand fast",75,85],["G1722","in",86,88],["G2962","the Lord",89,97],["G0027","my dearly beloved",99,116]]},"4:2":{"text":"I beseech Euodias, and beseech Syntyche, that they be of the same mind in the Lord.","words":[["G3870","I beseech",0,9],["G2136","Euodias",10,17],["G2532","and",19,22],["G3870","beseech",23,30],["G4941","Syntyche",31,39],["G5426","that they be of",41,56],["G0846","the same",57,65],["G5426","mind",66,70],["G1722","in",71,73],["G2962","the Lord",74,82]]},"4:3":{"text":"And I intreat thee also, true yokefellow, help those women which laboured with me in the gospel, with Clement also, and with other my fellowlabourers, whose names are in the book of life.","words":[["G2532","And",0,3],["G2065","I intreat",4,13],["G4571","thee",14,18],["G2532","also",19,23],["G1103","true",25,29],["G4805","yokefellow",30,40],["G4815","help",42,46],["G0846","those women",47,58],["G3748","which",59,64],["G4866","laboured",65,73],["G3427","with me",74,81],["G1722","in",82,84],["G2098","the gospel",85,95],["G3326","with",97,101],["G2815","Clement",102,109],["G2532","also",110,114],["G2532","and",116,119],["G3062","with other",120,130],["G3450","my",131,133],["G4904","fellowlabourers",134,149],["G3739","whose",151,156],["G3686","names",157,162],["G1722","are in",163,169],["G0976","the book",170,178],["G2222","of life",179,186]]},"4:4":{"text":"Rejoice in the Lord alway: and again I say, Rejoice.","words":[["G5463","Rejoice",0,7],["G1722","in",8,10],["G2962","the Lord",11,19],["G3842","alway",20,25],["G3825","and again",27,36],["G2046","I say",37,42],["G5463","Rejoice",44,51]]},"4:5":{"text":"Let your moderation be known unto all men. The Lord is at hand.","words":[["G1097","Let",0,3],["G5216","your",4,8],["G1933","moderation",9,19],["G1097","be known",20,28],["G3956","unto all",29,37],["G0444","men",38,41],["G2962","The Lord",43,51],["G1451","is at hand",52,62]]},"4:6":{"text":"Be careful for nothing; but in every thing by prayer and supplication with thanksgiving let your requests be made known unto God.","words":[["G3309","Be careful",0,10],["G3367","for nothing",11,22],["G0235","but",24,27],["G1722","in",28,30],["G3956","every thing",31,42],["G4335","by prayer",43,52],["G2532","and",53,56],["G1162","supplication",57,69],["G3326","with",70,74],["G2169","thanksgiving",75,87],["G1107","let",88,91],["G5216","your",92,96],["G0155","requests",97,105],["G1107","be made known",106,119],["G4314","unto",120,124],["G2316","God",125,128]]},"4:7":{"text":"And the peace of God, which passeth all understanding, shall keep your hearts and minds through Christ Jesus.","words":[["G2532","And",0,3],["G1515","the peace",4,13],["G2316","of God",14,20],["G3588","which",22,27],["G5242","passeth",28,35],["G3956","all",36,39],["G3563","understanding",40,53],["G5432","shall keep",55,65],["G5216","your",66,70],["G2588","hearts",71,77],["G2532","and",78,81],["G5216","minds",82,87],["G3540","minds",82,87],["G1722","through",88,95],["G5547","Christ",96,102],["G2424","Jesus",103,108]]},"4:8":{"text":"Finally, brethren, whatsoever things are true, whatsoever things are honest, whatsoever things are just, whatsoever things are pure, whatsoever things are lovely, whatsoever things are of good report; if there be any virtue, and if there be any praise, think on these things.","words":[["G3063","Finally",0,7],["G0080","brethren",9,17],["G3745","whatsoever things",19,36],["G2076","are",37,40],["G0227","true",41,45],["G3745","whatsoever things",47,64],["G4586","are honest",65,75],["G3745","whatsoever things",77,94],["G1342","are just",95,103],["G3745","whatsoever things",105,122],["G0053","are pure",123,131],["G3745","whatsoever things",133,150],["G4375","are lovely",151,161],["G3745","whatsoever things",163,180],["G2163","are of good report",181,199],["G1536","if there be any",201,216],["G0703","virtue",217,223],["G2532","and",225,228],["G1536","if there be any",229,244],["G1868","praise",245,251],["G3049","think",253,258],["G5023","on these things",259,274]]},"4:9":{"text":"Those things, which ye have both learned, and received, and heard, and seen in me, do: and the God of peace shall be with you.","words":[["G5023","Those things",0,12],["G3739","which",14,19],["G3129","ye have",20,27],["G2532","both",28,32],["G3129","learned",33,40],["G2532","and",42,45],["G3880","received",46,54],["G2532","and",56,59],["G0191","heard",60,65],["G2532","and",67,70],["G1492","seen",71,75],["G1722","in",76,78],["G1698","me",79,81],["G4238","do",83,85],["G2532","and",87,90],["G2316","the God",91,98],["G1515","of peace",99,107],["G2071","shall be",108,116],["G3326","with",117,121],["G5216","you",122,125]]},"4:10":{"text":"But I rejoiced in the Lord greatly, that now at the last your care of me hath flourished again; wherein ye were also careful, but ye lacked opportunity.","words":[["G1161","But",0,3],["G5463","I rejoiced",4,14],["G1722","in",15,17],["G2962","the Lord",18,26],["G3171","greatly",27,34],["G3754","that",36,40],["G2235","now",41,44],["G4218","at the last",45,56],["G5426","your care",57,66],["G0330","your care",57,66],["G5228","of",67,69],["G1700","me",70,72],["G0330","hath flourished again",73,94],["G1909","wherein",96,103],["G3739","wherein",96,103],["G5426","ye were",104,111],["G2532","also",112,116],["G5426","careful",117,124],["G1161","but",126,129],["G0170","ye lacked opportunity",130,151]]},"4:11":{"text":"Not that I speak in respect of want: for I have learned, in whatsoever state I am, therewith to be content.","words":[["G3756","Not",0,3],["G3004","that I speak",4,16],["G3754","in respect",17,27],["G2596","in respect",17,27],["G5304","of want",28,35],["G1063","for",37,40],["G1473","I",41,42],["G3129","have learned",43,55],["G1722","in",57,59],["G3739","whatsoever state",60,76],["G1510","I am",77,81],["G1511","therewith to be",83,98],["G0842","content",99,106]]},"4:12":{"text":"I know both how to be abased, and I know how to abound: every where and in all things I am instructed both to be full and to be hungry, both to abound and to suffer need.","words":[["G1161","",-1,-1],["G1492","I know",0,6],["G5013","both how to be abased",7,28],["G2532","and",30,33],["G1492","I know",34,40],["G4052","how to abound",41,54],["G1722","every where",56,67],["G3956","every where",56,67],["G2532","and",68,71],["G1722","in",72,74],["G3956","all things",75,85],["G3453","I am instructed",86,101],["G2532","both",102,106],["G5526","to be full",107,117],["G2532","and",118,121],["G3983","to be hungry",122,134],["G2532","both",136,140],["G4052","to abound",141,150],["G2532","and",151,154],["G5302","to suffer need",155,169]]},"4:13":{"text":"I can do all things through Christ which strengtheneth me.","words":[["G2480","I can do",0,8],["G3956","all things",9,19],["G1722","through",20,27],["G5547","Christ",28,34],["G3588","which",35,40],["G1743","strengtheneth",41,54],["G3165","me",55,57]]},"4:14":{"text":"Notwithstanding ye have well done, that ye did communicate with my affliction.","words":[["G4133","Notwithstanding",0,15],["G2573","ye have well",16,28],["G4160","done",29,33],["G4790","that ye did communicate with",35,63],["G3450","my",64,66],["G2347","affliction",67,77]]},"4:15":{"text":"Now ye Philippians know also, that in the beginning of the gospel, when I departed from Macedonia, no church communicated with me as concerning giving and receiving, but ye only.","words":[["G1161","Now",0,3],["G5210","ye",4,6],["G5374","Philippians",7,18],["G1492","know",19,23],["G2532","also",24,28],["G3754","that",30,34],["G1722","in",35,37],["G0746","the beginning",38,51],["G2098","of the gospel",52,65],["G3753","when",67,71],["G1831","I departed",72,82],["G0575","from",83,87],["G3109","Macedonia",88,97],["G3762","no",99,101],["G1577","church",102,108],["G2841","communicated with",109,126],["G3427","me",127,129],["G1519","as",130,132],["G3056","concerning",133,143],["G1394","giving",144,150],["G2532","and",151,154],["G3028","receiving",155,164],["G1508","but",166,169],["G5210","ye",170,172],["G3441","only",173,177]]},"4:16":{"text":"For even in Thessalonica ye sent once and again unto my necessity.","words":[["G3754","For",0,3],["G2532","even",4,8],["G1722","in",9,11],["G2332","Thessalonica",12,24],["G3992","ye sent",25,32],["G2532","once",33,37],["G0530","once",33,37],["G2532","and",38,41],["G1364","again",42,47],["G1519","unto",48,52],["G3427","my",53,55],["G5532","necessity",56,65]]},"4:17":{"text":"Not because I desire a gift: but I desire fruit that may abound to your account.","words":[["G3756","Not",0,3],["G3754","because",4,11],["G1934","I desire",12,20],["G1390","a gift",21,27],["G0235","but",29,32],["G1934","I desire",33,41],["G2590","fruit",42,47],["G4121","that may abound",48,63],["G1519","to",64,66],["G5216","your",67,71],["G3056","account",72,79]]},"4:18":{"text":"But I have all, and abound: I am full, having received of Epaphroditus the things which were sent from you, an odour of a sweet smell, a sacrifice acceptable, wellpleasing to God.","words":[["G1161","But",0,3],["G0568","I have",4,10],["G3956","all",11,14],["G2532","and",16,19],["G4052","abound",20,26],["G4137","I am full",28,37],["G1209","having received",39,54],["G3844","of",55,57],["G1891","Epaphroditus",58,70],["G3844","the things which were sent from",71,102],["G5216","you",103,106],["G3744","an odour",108,116],["G2175","of a sweet smell",117,133],["G2378","a sacrifice",135,146],["G1184","acceptable",147,157],["G2101","wellpleasing",159,171],["G2316","to God",172,178]]},"4:19":{"text":"But my God shall supply all your need according to his riches in glory by Christ Jesus.","words":[["G1161","But",0,3],["G3450","my",4,6],["G2316","God",7,10],["G4137","shall supply",11,23],["G3956","all",24,27],["G5216","your",28,32],["G5532","need",33,37],["G2596","according to",38,50],["G0846","his",51,54],["G4149","riches",55,61],["G1722","in",62,64],["G1391","glory",65,70],["G1722","by",71,73],["G5547","Christ",74,80],["G2424","Jesus",81,86]]},"4:20":{"text":"Now unto God and our Father be glory for ever and ever. Amen.","words":[["G1161","Now",0,3],["G2316","unto God",4,12],["G2532","and",13,16],["G2257","our",17,20],["G3962","Father",21,27],["G1391","be glory",28,36],["G1519","for",37,40],["G0165","ever",41,45],["G0165","and ever",46,54],["G0281","Amen",56,60]]},"4:21":{"text":"Salute every saint in Christ Jesus. The brethren which are with me greet you.","words":[["G0782","Salute",0,6],["G3956","every",7,12],["G0040","saint",13,18],["G1722","in",19,21],["G5547","Christ",22,28],["G2424","Jesus",29,34],["G0080","The brethren",36,48],["G4862","which are with",49,63],["G1698","me",64,66],["G0782","greet",67,72],["G5209","you",73,76]]},"4:22":{"text":"All the saints salute you, chiefly they that are of Caesar's household.","words":[["G3956","All",0,3],["G0040","the saints",4,14],["G0782","salute",15,21],["G5209","you",22,25],["G1161","",-1,-1],["G3122","chiefly",27,34],["G1537","they that are of",35,51],["G2541","Caesar's",52,60],["G3614","household",61,70]]},"4:23":{"text":"The grace of our Lord Jesus Christ be with you all. Amen.","words":[["G5485","The grace",0,9],["G2257","of our",10,16],["G2962","Lord",17,21],["G2424","Jesus",22,27],["G5547","Christ",28,34],["G3326","be with",35,42],["G5216","you",43,46],["G3956","all",47,50],["G0281","Amen",52,56]]}}};
